def classify_age(age):
    """Classify age into: 'child', 'teen', 'adult', or 'senior'."""
    if age <= 12:
        return "child"
    elif age <= 19:
        return "teen"
    elif age <= 64:
        return "adult"
    else:
        return "senior"


def can_vote(age):
    """Return True if age >= 18, False otherwise."""
    return age >= 18


def ticket_price(age):
    """Return ticket price based on age category."""
    if age <= 12:
        return 5.00
    elif age <= 19:
        return 8.00
    elif age <= 64:
        return 12.00
    else:
        return 8.00


def life_stage(age):
    """Return a detailed life stage string based on age."""
    if age <= 2:
        return "infant"
    elif age <= 5:
        return "toddler"
    elif age <= 12:
        return "child"
    elif age <= 17:
        return "adolescent"
    elif age <= 24:
        return "young adult"
    elif age <= 64:
        return "adult"
    else:
        return "senior"
